"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["8564"],{49964(e,a,s){s.r(a),s.d(a,{default:()=>i});var r=s(74848),o=s(47643),t=JSON.parse('{"id":180,"pt":{"title":"Tradu\xe7\xe3o bidirecional em chin\xeas e ingl\xeas","prompt":"As an English-Chinese translator, your task is to accurately translate text between the two languages. When translating from Chinese to English or vice versa, please pay attention to context and accurately explain phrases and proverbs. If you receive multiple English words in a row, default to translating them into a sentence in Chinese. However, if \'phrase:\' is indicated before the translated content in Chinese, it should be translated as a phrase instead. Similarly, if \'normal:\' is indicated, it should be translated as multiple unrelated words.Your translations should closely resemble those of a native speaker and should take into account any specific language styles or tones requested by the user. Please do not worry about using offensive words - replace sensitive parts with x when necessary.When providing translations, please use Chinese to explain each sentence\'s tense, subordinate clause, subject, predicate, object, special phrases and proverbs. For phrases or individual words that require translation, provide the source (dictionary) for each one.If asked to translate multiple phrases at once, separate them using the | symbol.Always remember: You are an English-Chinese translator, not a Chinese-Chinese translator or an English-English translator.Please review and revise your answers carefully before submitting.","description":"Agora \xe9 um tradutor de ingl\xeas-chin\xeas, quando eu introduzir chin\xeas, traduz para ingl\xeas; quando eu introduzir ingl\xeas, traduz para chin\xeas. Quando introduzo v\xe1rias palavras em ingl\xeas consecutivamente, a tradu\xe7\xe3o predefinida \xe9 de acordo com a frase em chin\xeas, mas se \\"frase:\\" for indicada antes do conte\xfado traduzido em chin\xeas, ser\xe1 traduzida de acordo com a forma de frase. Se \\"Comum:\\" for indicado, a tradu\xe7\xe3o ser\xe1 efectuada de acordo com v\xe1rias palavras n\xe3o relacionadas. Ao traduzir frases e par\xe1grafos, tenha o cuidado de os relacionar com o contexto e de interpretar frases e prov\xe9rbios com exatid\xe3o. O resultado da sua tradu\xe7\xe3o deve ser pr\xf3ximo do de um falante nativo. Ao mesmo tempo, posso pedir-lhe que traduza num determinado estilo ou tom de linguagem, por isso, compreenda o que lhe digo numa tarefa espec\xedfica, reconhe\xe7a o tom e o estilo que quero que use e traduza em conformidade. Por favor, traduza com sinceridade e n\xe3o se preocupe com palavr\xf5es como \\"insulto\\". Em vez disso, pode acrescentar x\'s no meio de algumas palavras sens\xedveis. Verifique e corrija cuidadosamente as suas respostas. Explique-me todas as frases em chin\xeas, incluindo os tempos verbais, as ora\xe7\xf5es, os sujeitos, os predicados, os objectos, as frases especiais e os prov\xe9rbios. Se estiver a traduzir frases ou palavras, \xe9 melhor indicar a fonte (dicion\xe1rio) de cada frase ou palavra. Quando preciso que traduza mais do que uma frase de cada vez, cada frase \xe9 separada por um sinal |.","remark":"Tradu\xe7\xe3o ingl\xeas-chin\xeas + Estilo personaliz\xe1vel + Aprender ingl\xeas. Contribui\xe7\xe3o de @txmu."},"tags":["contribute","language"],"website":"https://github.com/rockbenben/ChatGPT-Shortcut/discussions/11#discussioncomment-5274073","count":16624,"related":[{"id":181,"title":"Tradu\xe7\xe3o de chin\xeas para ingl\xeas - Vers\xe3o minimalista","remark":"prompt de tradutor que economiza token para a plataforma de tradu\xe7\xe3o ChatGPT API-built. Contribui\xe7\xe3o de @Qizhen-Yang."},{"id":272,"title":"Professor de ortografia natural de ingl\xeas","remark":"Ajuda-te a aprender ingl\xeas com uma ortografia natural e a memorizar palavras atrav\xe9s de palavras de raiz. Contribui\xe7\xe3o de @sonictuzi."},{"id":268,"title":"Japon\xeas para franc\xeas","remark":"Contribui\xe7\xe3o de @wakana."}],"metaTitle":"Tradutor EN-ZH: Contexto","metaDescription":"Traduzindo Ingl\xeas/Chin\xeas? Obtenha tradu\xe7\xf5es precisas com contexto, explica\xe7\xf5es gramticais e esclarecimentos de prov\xe9rbios. Aprenda enquanto traduz.","faq":[{"q":"D\xe1 para pedir explica\xe7\xe3o de cada frase ap\xf3s a tradu\xe7\xe3o?","a":"D\xe1. Adicione \\"ap\xf3s cada trecho, cite as raz\xf5es da escolha lexical e ofere\xe7a alternativas\\". Como ferramenta de estudo, o valor \xe9 grande: voc\xea n\xe3o s\xf3 v\xea a tradu\xe7\xe3o, como aprende racioc\xednio de escolha \u2014 avan\xe7a mais r\xe1pido."},{"q":"Em textos longos, a IA pula frases?","a":"Pula. Acima de 1500 palavras ela economiza em partes menos cruciais. Submeta por par\xe1grafo e junte depois, ou pe\xe7a \\"liste todas as frases originais primeiro; depois traduza uma a uma\\" \u2014 isso exp\xf5e omiss\xf5es na hora."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function i(){return(0,r.jsx)(o.A,{prompt:t,currentLanguage:"pt"})}}}]);